/// Tell the tmp_path factory the explicit --basetemp directory (cleared at
/// session start, kept after the run, like pytest).
pub fn configure_basetemp(py: Python<'_>, path: &str) {
    let _ = py
        .import("pytest._tmp_path")
        .and_then(|m| m.call_method1("configure", (path,)));
}

/// Tell the assert-rewrite explainer the -v level (full iterable diffs
/// need -v, identical dict items unfold at -vv, like pytest).
pub fn set_assertion_verbosity(py: Python<'_>, level: u8) {
    let _ = py
        .import("pytest._rewrite")
        .and_then(|m| m.call_method1("set_verbosity", (level,)));
}

/// Pass the truncation_limit_lines / truncation_limit_chars ini values to
/// the assert-rewrite explainer (None keeps pytest's defaults: 8 lines,
/// 640 chars).
pub fn set_assertion_truncation(py: Python<'_>, lines: Option<&str>, chars: Option<&str>) {
    let parse = |value: Option<&str>| value.and_then(|s| s.trim().parse::<i64>().ok());
    let _ = py
        .import("pytest._rewrite")
        .and_then(|m| m.call_method1("set_truncation_limits", (parse(lines), parse(chars))));
}

/// The Session proxy passed to pytest_sessionstart /
/// pytest_collection_finish python hooks (config + shouldfail + items).
pub fn make_session_proxy(py: Python<'_>, config: &crate::config::Config) -> PyResult<Py<PyAny>> {
    let config_proxy = make_py_config(py, config)?;
    Ok(py
        .import("pytest._node")?
        .getattr("_NodeSession")?
        .call1((config_proxy,))?
        .unbind())
}

/// Publish the collected items on the session proxy (session.items /
/// session.testscollected), once collection settles.
pub fn set_session_items(py: Python<'_>, items: &[crate::collect::TestItem]) -> PyResult<()> {
    let nodes = pyo3::types::PyList::empty(py);
    for item in items {
        nodes.append(make_node(py, item)?)?;
    }
    py.import("pytest._node")?
        .getattr("set_session_items")?
        .call1((nodes,))?;
    Ok(())
}

/// Upstream xdist's default auto/logical worker-count detection: the
/// PYTEST_XDIST_AUTO_NUM_WORKERS env override, psutil if installed (the
/// pytest-xdist[psutil] extra), then sched_getaffinity/cpu_count.
pub fn xdist_auto_num_workers(py: Python<'_>, logical: bool) -> usize {
    py.import("pytest._xdist_fixtures")
        .and_then(|m| m.call_method1("auto_num_workers", (logical,)))
        .and_then(|n| n.extract())
        .unwrap_or_else(|_| {
            std::thread::available_parallelism()
                .map(std::num::NonZero::get)
                .unwrap_or(1)
        })
}

/// Set the worker process title (the pytest-xdist[setproctitle] extra);
/// best-effort no-op when setproctitle is not installed. Availability is
/// probed once per process: the per-item call must stay free when the
/// extra is absent.
pub fn worker_set_title(py: Python<'_>, title: &str) {
    static AVAILABLE: std::sync::OnceLock<bool> = std::sync::OnceLock::new();
    let available = *AVAILABLE.get_or_init(|| py.import("setproctitle").is_ok());
    if !available {
        return;
    }
    let _ = py
        .import("pytest._xdist_fixtures")
        .and_then(|m| m.call_method1("set_worker_title", (title,)));
}

/// Register the default 'terminalreporter' plugin (the stand-in that
/// reporter-replacing plugins like pytest-sugar unregister). Must run
/// before python pytest_configure hooks fire.
pub fn reporter_setup(py: Python<'_>, config: &crate::config::Config) -> PyResult<()> {
    let config_proxy = make_py_config(py, config)?;
    py.import("pytest._reporter")?
        .getattr("setup")?
        .call1((config_proxy,))?;
    Ok(())
}

/// The plugin object that replaced 'terminalreporter' during configure,
/// or None when terminal output stays native.
pub fn reporter_replacement(py: Python<'_>) -> Option<Py<PyAny>> {
    let result = py
        .import("pytest._reporter")
        .and_then(|m| m.getattr("replacement"))
        .and_then(|f| f.call0());
    match result {
        Ok(reporter) if !reporter.is_none() => Some(reporter.unbind()),
        _ => None,
    }
}

/// Drive the replacement reporter's pytest_sessionstart (it owns the
/// session header in delegated mode).
pub fn reporter_sessionstart(py: Python<'_>, config: &crate::config::Config) {
    let result = (|| -> PyResult<()> {
        let session = make_session_proxy(py, config)?;
        py.import("pytest._reporter")?
            .getattr("sessionstart")?
            .call1((session,))?;
        Ok(())
    })();
    if let Err(err) = result {
        eprintln!("INTERNAL ERROR: {}", format_exception(py, &err));
    }
}

/// Drive the replacement reporter's pytest_collection_finish ("collected N
/// items" line). `numcollected` includes deselected items.
pub fn reporter_collection_finish(
    py: Python<'_>,
    config: &crate::config::Config,
    numcollected: usize,
) {
    let result = (|| -> PyResult<()> {
        let session = make_session_proxy(py, config)?;
        py.import("pytest._reporter")?
            .getattr("collection_finish")?
            .call1((session, numcollected))?;
        Ok(())
    })();
    if let Err(err) = result {
        eprintln!("INTERNAL ERROR: {}", format_exception(py, &err));
    }
}

/// Drive the replacement reporter's pytest_deselected (stats bookkeeping
